-- Sprint 3.5 post-close repair: fix automatic workout scheduled_date/weekday mismatches.
--
-- Scope:
-- - Only automatic workouts generated by routine logic.
-- - Never touches manual workouts.
-- - Recomputes scheduled_date from the Monday of the current scheduled_date week
--   plus the stored weekday, where weekday is 1=Monday ... 7=Sunday.

UPDATE public.workouts
SET scheduled_date = (
  scheduled_date::date
  - (EXTRACT(ISODOW FROM scheduled_date::date)::int - 1)
  + (weekday - 1)
)::date
WHERE tipo = 'automatico'
  AND scheduled_date IS NOT NULL
  AND weekday IS NOT NULL
  AND weekday BETWEEN 1 AND 7
  AND EXTRACT(ISODOW FROM scheduled_date::date)::int <> weekday;
